package com.pdp.mysql.project;
import com.pdp.project.domain.ProjectStage; import com.pdp.project.port.ProjectStageRepository; import com.pdp.shared.concurrency.*; import java.util.*; import org.springframework.stereotype.Repository;
@Repository public final class MysqlProjectStageRepository implements ProjectStageRepository { private final ProjectStageMapper mapper; public MysqlProjectStageRepository(ProjectStageMapper mapper){this.mapper=mapper;} public Optional<ProjectStage> findById(UUID w,UUID p,UUID id){return Optional.ofNullable(mapper.findById(w,p,id)).map(ProjectStageRow::domain);} public List<ProjectStage> findByProjectId(UUID w,UUID p){return mapper.findByProjectId(w,p).stream().map(ProjectStageRow::domain).toList();} public ProjectStage insert(ProjectStage s){mapper.insert(ProjectStageRow.from(s));return s;} public ProjectStage update(ProjectStage s,Revision e){if(mapper.update(ProjectStageRow.from(s))==0)throw new ConcurrencyConflictException(e,e);return s;} }
